import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.ZhLefgN8.js";const p=JSON.parse('{"title":"市场深度","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/desktop-tools/market-depth.md","filePath":"zh-CN/stock-trading/desktop-tools/market-depth.md"}'),i={name:"stock-trading/desktop-tools/market-depth.md"};function o(h,a,d,n,s,c){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="市场深度" tabindex="-1">市场深度 <a class="header-anchor" href="#市场深度" aria-label="Permalink to &quot;市场深度&quot;">​</a></h1><p>市场深度显示买卖挂单分布、下单、改单、撤单操作及持仓信息显示。</p><h2 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h2><p>市场深度（DOM，Depth of Market）展示买卖双方在不同价格水平的挂单数量，帮助用户直观了解当前市场供需分布。该功能特别适合日内交易者使用。美股支持 60 档深度数据，港股支持 10 档深度数据。无高级行情权限时，仍可查看价格信息，但无法看到各档位的挂单量（盘口数据）。</p><h2 id="主要用途" tabindex="-1">主要用途 <a class="header-anchor" href="#主要用途" aria-label="Permalink to &quot;主要用途&quot;">​</a></h2><ul><li>识别关键支撑位和阻力位</li><li>发现买卖力量不平衡的价格区域</li><li>评估市场流动性，判断成交难易程度</li></ul><h2 id="开启入口" tabindex="-1">开启入口 <a class="header-anchor" href="#开启入口" aria-label="Permalink to &quot;开启入口&quot;">​</a></h2><ul><li>入口一：日内交易面板内直接切换到市场深度视图</li><li>入口二：组件工具箱 &gt; 交易 &gt; 市场深度</li></ul><h2 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h2><h3 id="下单" tabindex="-1">下单 <a class="header-anchor" href="#下单" aria-label="Permalink to &quot;下单&quot;">​</a></h3><ol><li>在数量输入框设置委托数量</li><li>点击目标价格行，即可提交限价单</li></ol><h3 id="改单" tabindex="-1">改单 <a class="header-anchor" href="#改单" aria-label="Permalink to &quot;改单&quot;">​</a></h3><p>拖动已有委托单到目标价格行，即可完成改单。</p><h3 id="撤单" tabindex="-1">撤单 <a class="header-anchor" href="#撤单" aria-label="Permalink to &quot;撤单&quot;">​</a></h3><ul><li>单笔撤单：点击委托单右侧的 X 按钮</li><li>批量撤单：点击批量撤单按钮，一次性撤销全部委托</li></ul><h3 id="价格定位" tabindex="-1">价格定位 <a class="header-anchor" href="#价格定位" aria-label="Permalink to &quot;价格定位&quot;">​</a></h3><ul><li>回到最新价：点击后视图自动滚动到当前最新成交价位置</li><li>锁定最新价：开启后，视图始终跟随最新价自动滚动，保持最新价可见</li></ul><h2 id="附加单设置" tabindex="-1">附加单设置 <a class="header-anchor" href="#附加单设置" aria-label="Permalink to &quot;附加单设置&quot;">​</a></h2><p>附加单在主委托成交后自动触发，支持 3 种价格设置方式：</p><h3 id="档位" tabindex="-1">档位 <a class="header-anchor" href="#档位" aria-label="Permalink to &quot;档位&quot;">​</a></h3><p>以最小价格变动单位（tick）为基础，设置档数倍数。</p><p>示例：最小变动单位 0.01 元，止损设为 -500 档，止损触发价 = 委托价 - 5 元。</p><h3 id="价差" tabindex="-1">价差 <a class="header-anchor" href="#价差" aria-label="Permalink to &quot;价差&quot;">​</a></h3><p>以委托价为基准，设置固定的价格差值。</p><p>示例：委托价 100 元，止损价差 -5 元，止损触发价 = 95 元。</p><h3 id="价格" tabindex="-1">价格 <a class="header-anchor" href="#价格" aria-label="Permalink to &quot;价格&quot;">​</a></h3><p>直接填写止盈或止损的目标价格。</p><p>示例：买入委托价 100 元，止损直接设置为 95 元。</p><h2 id="持仓信息" tabindex="-1">持仓信息 <a class="header-anchor" href="#持仓信息" aria-label="Permalink to &quot;持仓信息&quot;">​</a></h2><p>市场深度界面显示当前持仓数量及持仓成本价，方便实时对照盈亏。建议与图表交易组件配合使用，结合价格走势和盘口深度综合判断买卖时机。</p>',30)])])}const b=e(i,[["render",o]]);export{p as __pageData,b as default};
